203→// Login authenticates with the API and returns a token and user info.
204→func (c *Client) Login(ctx context.Context, email, password string) (string, UserInfo, error) {
205→	var resp struct {
206→		Login struct {
207→			Token string   `json:"token"`
208→			User  UserInfo `json:"user"`
209→		} `json:"login"`
210→	}
211→
212→	vars := map[string]any{
213→		"input": map[string]any{
214→			"email":    email,
215→			"password": password,
216→		},
217→	}
218→
219→	if err := c.Do(ctx, loginMutation, vars, &resp); err != nil {
220→		return "", UserInfo{}, err
221→	}
222→
223→	return resp.Login.Token, resp.Login.User, nil
224→}
