291→		Items SearchResult `json:"items"`
292→	}
293→
294→	vars := map[string]any{
295→		"limit":  opts.Limit,
296→		"offset": opts.Offset,
297→	}
298→	if len(opts.Types) > 0 {
299→		vars["filter"] = map[string]any{"types": toUpperStrings(opts.Types)}
300→	}
301→	if opts.Sort != "" {
302→		vars["sort"] = map[string]any{
303→			"field":     strings.ToUpper(opts.Sort),
304→			"direction": "DESC",
305→		}
306→	}
307→
308→	if err := c.Do(ctx, listQuery, vars, &resp); err != nil {
309→		return nil, err
310→	}
311→	return &resp.Items, nil
