314→// toUpperStrings converts a slice of strings to uppercase.
315→func toUpperStrings(ss []string) []string {
316→	out := make([]string, len(ss))
317→	for i, s := range ss {
318→		out[i] = strings.ToUpper(s)
319→	}
320→	return out
321→}
